#define HARBOUR_FORMS_FROM(v1)                                                                                             \
    if (auto HARBOUR_FORM_IT = HARBOUR_FORM_VAR.find(#v1); HARBOUR_FORM_IT != HARBOUR_FORM_VAR.end()) {                    \
        if (auto HARBOUR_FORM_CVTD = harbour_cvt_s2t<decltype(HARBOUR_DESERIALIZABLE_TYPE.v1)>(HARBOUR_FORM_IT->second)) { \
            HARBOUR_DESERIALIZABLE_TYPE.v1 = *HARBOUR_FORM_CVTD;                                                           \
        } else {                                                                                                           \
            return {};                                                                                                     \
        }                                                                                                                  \
    } else {                                                                                                               \
        return {};                                                                                                         \
    }

// Construct a from_form method for Type
#define HARBOUR_FROM_FORM(Type, ...)                                               \
    static auto from_form(const Form &HARBOUR_FORM_VAR) -> std::optional<Type> {   \
        Type HARBOUR_DESERIALIZABLE_TYPE;                                          \
        HARBOUR_FORMS_EXPAND(HARBOUR_FORMS_PASTE(HARBOUR_FORMS_FROM, __VA_ARGS__)) \
        return HARBOUR_DESERIALIZABLE_TYPE;                                        \
    }

// Convert a std::string into type T, return {} if unable to convert
template<typename T>
auto harbour_cvt_s2t(const std::string &str) -> std::optional<T> {
    std::istringstream iss(str);
    T v;

    if constexpr (std::is_same_v<std::string, T>) {
        return str;
    }

    if (iss >> v && iss.eof()) {
        return v;
    }

    return {};
}

// Form data used inside a Request
using Form = std::unordered_map<std::string, std::string>;

namespace Forms {
    // Get form data from a Request bodies last line
    auto parse(const std::string &data) -> Form {
        Form form;
        std::istringstream stream(data);
        std::string token;

        // form data comes in as key1=value&key2=value
        // split each key value pair at the '&'
        // then convert each token into a k/v pair
        // store the k/v inside of a Form type
        while (std::getline(stream, token, '&')) {
            const auto equal = token.find('=');
            if (equal != std::string::npos) {
                const auto k = token.substr(0, equal);
                const auto v = token.substr(equal + 1);
                form[k]      = v;
            }
        }

        return form;
    }
}// namespace Forms